#!/bin/bash
set -e
echo "🚀 Deploy v13: Feature Enhancements"
echo "  1. Performance section always visible + top 3 recommendations"
echo "  2. Status column truncation fix"
echo "  3. White dot removal from AI Visibility"
echo "  4. Custom AI query input"
echo "  5. AI Visibility top 3 recommendations"
echo ""

cd ~/chaos_tester

# Decode files to ROOT-level paths (not chaos_tester/ subdirectory!)
echo "📄 Writing templates/report.html..."
echo '' | base64 -d > templates/report.html

echo "📄 Writing modules/performance.py..."
echo '' | base64 -d > modules/performance.py

echo "📄 Writing app.py..."
echo '' | base64 -d > app.py

echo "📄 Writing templates/dashboard.html..."
echo '' | base64 -d > templates/dashboard.html

# Verify Python syntax
echo "🔍 Verifying Python syntax..."
python3 -c "import py_compile; py_compile.compile('app.py', doraise=True); print('  app.py ✓')"
python3 -c "import py_compile; py_compile.compile('modules/performance.py', doraise=True); print('  performance.py ✓')"

# Update Dockerfile cache bust
echo "📦 Updating Dockerfile cache bust..."
sed -i 's/^ARG CACHE_BUST=.*/ARG CACHE_BUST=1773521479/' Dockerfile
if ! grep -q 'ARG CACHE_BUST' Dockerfile; then
  sed -i '/^COPY \. \.\/chaos_tester\//i ARG CACHE_BUST=1773521479' Dockerfile
fi

# Remove duplicate chaos_tester/ subdirectory if it exists
if [ -d "chaos_tester" ]; then
  echo "🧹 Removing duplicate chaos_tester/ subdirectory..."
  rm -rf chaos_tester/
fi

# Commit and push
echo "📤 Committing and pushing to GitHub..."
git add -A
git commit -m "feat: add performance recommendations, fix status column, AI visibility enhancements

- Performance section always visible with top 3 Lighthouse recommendations
- Status column width increased, truncation removed for Status/Severity
- White dot indicator removed from AI Visibility platform column
- Custom AI query input (runs against all 4 AI models via Perplexity)
- AI Visibility top 3 actionable recommendations based on results data
- Cache buster bumped to v4"
git push origin main

# Deploy to Cloud Run
echo "☁️ Deploying to Cloud Run..."
gcloud run deploy chaos-tester \
  --source . \
  --region us-central1 \
  --allow-unauthenticated \
  --port 8080 \
  --memory 512Mi

echo ""
echo "✅ Deploy v13 complete! Site should be live at https://website-auditor.io"
echo "   Please allow 1-2 minutes for the new revision to become active."
